+     */
+    async clear() {
+        await this.init();
+        await this.storage.delete(this.cacheDir);
+        this._stats = { hits: 0, misses: 0, bytesFromCache: 0, bytesFromNetwork: 0 };
+        console.log(`[HotTierCache] Cleared all cache`);
+    }
